  return <div>{id}</div>;
}

// Решение: Используйте useEffect для отложенного рендера
export function GoodComponent() {
  const [mounted, setMounted] = useState(false);
  useEffect(() => setMounted(true), []);

  return mounted ? <div>{Math.random()}</div> : null;
}

// Альтернатива: suppressHydrationWarning
<div suppressHydrationWarning>{new Date().toISOString()}</div>
```

**Типичная ошибка:** Игнорировать предупреждения вместо исправления причин—некоторые мисматчи указывают на реальные логические ошибки.

answer.en:
### Custom React Renderers

React's reconciliation engine (Fiber) is platform-agnostic. Custom renderers implement the renderer interface to target non-DOM platforms (React Native, Canvas, WebGL, VR). They handle platform-specific host instances, mutations, and scheduling while reusing React's core reconciliation logic.

```typescript
// Simplified custom renderer for console output
const ConsoleRenderer = ReactReconciler({
  createInstance(type, props) {
    return { type, props, children: [] };
  },
  appendInitialChild(parent, child) {
    parent.children.push(child);
  },
  commitUpdate(instance, updatePayload, type, oldProps, newProps) {
    instance.props = newProps;
  },
  // ... other required methods
  scheduleTimeout: setTimeout,
  cancelTimeout: clearTimeout,
});

const root = ConsoleRenderer.createRoot({});
root.render(<MyComponent />);
```

**Common interview trap:** Thinking custom renderers are just DOM abstractions—they work for any medium: native apps, VR, 3D engines, IoT devices.

